db.add(Place(id='cmp7ewgd9002ojja2dnmjrj2z', place_type='RESTAURANT', name_uz='Samarqand Choyhonasi', name_ru='Самаркандская Чайхана', name_en='Samarqand Choyxona', description_uz="Samarqandning qadimiy choyxonasi — an'anaviy o'zbek madaniyatining yuragi. Yashil hovli, qadimiy daraxtlar va eng yaxshi pichoqnon. Choyni an'anaviy pichoqlarda tayyorlashadi.", description_ru='Старейшая чайхана Самарканда — сердце традиционной узбекской культуры. Зелёный двор, старые деревья и лучший самаркандский хлеб. Чай готовят в традиционных пиалах.', description_en='The oldest choyxona in Samarkand — the heart of traditional Uzbek culture. Green courtyard, ancient trees, and the best Samarkand bread. Tea is served in traditional bowls.', short_desc_uz="Samarqandning qadimiy an'anaviy choyxonasi", short_desc_ru='Старейшая традиционная чайхана Самарканда', short_desc_en="Samarkand's oldest traditional choyxona", address_uz="G'ijduvon yo'li, 3, Samarqand", address_ru='Гиждуванское шоссе, 3, Самарканд', address_en='Gijduvon Road, 3, Samarkand', city='Samarqand', latitude=39.658, longitude=66.949, phone='+998662340500', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.5, review_count=345, price_from=15000, price_to=60000, currency='UZS', is_halal=True, is_featured=False, working_hours='{"all": "07:00-21:00"}', view_count=12300, historical_period=None, owner_id=None, category_id='cmp7ewgbo000bjja2vzq2jc9m'))
db.add(Place(id='cmp7ewgdd002rjja24vepu4eu', place_type='PILGRIMAGE_SITE', name_uz='Gur-i Amir maqbarasi', name_ru='Мавзолей Гур-Эмир', name_en='Gur-e-Amir Mausoleum', description_uz="Buyuk Amir Temur va uning avlodlari dafn etilgan maqbara. 1403-1404 yillarda qurilgan bu ajoyib inshoot ko'k koshinlar bilan bezatilgan. Temuriylar me'morchiligining eng yuksak namunasi bo'lib, butun dunyo me'morchiligi tarixida muhim o'rin tutadi.", description_ru='Мавзолей, в котором похоронен великий Амир Тимур и его потомки. Построенный в 1403-1404 годах, этот удивительный памятник украшен голубой мозаикой. Высший образец архитектуры Тимуридов, занимающий важное место в истории мировой архитектуры.', description_en='The mausoleum where the great Amir Timur and his descendants are buried. Built in 1403–1404, this stunning monument is adorned with blue mosaics. The finest example of Timurid architecture, holding an important place in world architectural history.', short_desc_uz="Amir Temur maqbarasi — Temuriylar me'morchiligi durdonasi", short_desc_ru='Мавзолей Амира Тимура — жемчужина архитектуры Тимуридов', short_desc_en="Amir Timur's mausoleum — jewel of Timurid architecture", address_uz="Gur-i Amir ko'chasi, Samarqand", address_ru='улица Гур-Эмир, Самарканд', address_en='Gur-e-Amir Street, Samarkand', city='Samarqand', latitude=39.6489, longitude=66.9571, phone='+998662335800', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/gur-emir.jpg', gallery_images='["/images/pilgrimage/gur-emir-1.jpg", "/images/pilgrimage/gur-emir-2.jpg"]', rating=4.9, review_count=1890, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=72000, historical_period='1403-1404 yillar', owner_id=None, category_id='cmp7ewgbm0007jja2pnn47pqe'))
db.add(Place(id='cmp7ewgdd002tjja2y5p43rsg', place_type='PILGRIMAGE_SITE', name_uz='Registon maydoni', name_ru='Площадь Регистан', name_en='Registan Square', description_uz="Samarqandning eng mashhur me'moriy ansambli — Registon maydoni. XV-XVII asrlarda qurilgan Ulug'bek, Sherdor va Tilla-Qori madrasalari joylashgan. O'rta Osiyo me'morchiligining durdonasi bo'lib, UNESCO Jahon merosi ro'yxatiga kiritilgan. Ilk bor Temuriylar imperiyasi davrida shakllangan bu majmua o'rta asr sharq me'morchiligining eng yuksak namunasidir.", description_ru='Самая известная архитектурная ансамбль Самарканда — площадь Регистан. Здесь расположены медресе Улугбека, Шердор и Тилла-Кори, построенные в XV-XVII веках. Жемчужина среднеазиатской архитектуры, внесённая в список Всемирного наследия ЮНЕСКО. Впервые сформирована во время империи Тимуридов, этот комплекс является высшим образцом средневековой восточной архитектуры.', description_en='The most famous architectural ensemble of Samarkand — Registan Square. Home to the Ulugbek, Sher-Dor, and Tilla-Kori madrasahs built in the 15th–17th centuries. A jewel of Central Asian architecture and a UNESCO World Heritage Site. First formed during the Timurid Empire, this complex is the finest example of medieval Eastern architecture.', short_desc_uz="O'rta Osiyo me'morchiligining durdonasi", short_desc_ru='Жемчужина среднеазиатской архитектуры', short_desc_en='The jewel of Central Asian architecture', address_uz='Registon maydoni, Samarqand', address_ru='Площадь Регистан, Самарканд', address_en='Registan Square, Samarkand', city='Samarqand', latitude=39.6549, longitude=66.9597, phone='+998662335700', website='https://registan.uz', telegram=None, instagram=None, image_url='/images/pilgrimage/registan.jpg', gallery_images='["/images/pilgrimage/registan-1.jpg", "/images/pilgrimage/registan-2.jpg", "/images/pilgrimage/registan-3.jpg", "/images/pilgrimage/registan-4.jpg"]', rating=4.9, review_count=2340, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=89000, historical_period='XV-XVII asrlar', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdd002ujja20gch02h3', place_type='PILGRIMAGE_SITE', name_uz='Shohi-Zinda majmuasi', name_ru='Комплекс Шахи-Зинда', name_en='Shah-i-Zinda Complex', description_uz="XI-XIX asrlarga oid musulmon ziyoratgohlari majmuasi. Afsonaga ko'ra, Kusam ibn Abbos — Muhammad payg'ambarning amakivachchasi shu yerga dafn etilgan. 20 dan ortiq yodgorlik binolari bilan eng muhim ziyoratgohlardan biri. Ajoyib koshinlari va me'moriy bezaklari butun dunyo bo'ylab mashhur.", description_ru='Комплекс мусульманских паломнических мест XI-XIX веков. По легенде, Кусам ибн Аббас — двоюродный брат пророка Мухаммеда — похоронен здесь. Один из важнейших паломнических комплексов с более чем 20 памятниками архитектуры. Удивительная мозаика и архитектурный декор известны во всём мире.', description_en='A complex of Muslim pilgrimage sites dating from the 11th–19th centuries. According to legend, Qusam ibn Abbas — a cousin of the Prophet Muhammad — is buried here. One of the most important pilgrimage complexes with over 20 historic monuments. The stunning mosaics and architectural decorations are famous worldwide.', short_desc_uz='Islom dunyosining eng muqaddas ziyoratgohlardan biri', short_desc_ru='Одно из самых священных мест паломничества исламского мира', short_desc_en='One of the holiest pilgrimage sites in the Islamic world', address_uz="Shohi-Zinda ko'chasi, Samarqand", address_ru='улица Шахи-Зинда, Самарканд', address_en='Shah-i-Zinda Street, Samarkand', city='Samarqand', latitude=39.6494, longitude=66.9626, phone='+998662335900', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/shahi-zinda.jpg', gallery_images='["/images/pilgrimage/shahi-zinda-1.jpg", "/images/pilgrimage/shahi-zinda-2.jpg", "/images/pilgrimage/shahi-zinda-3.jpg"]', rating=4.9, review_count=1560, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-17:30"}', view_count=65000, historical_period='XI-XIX asrlar', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgde002wjja2v239szqn', place_type='PILGRIMAGE_SITE', name_uz="Ichan Qal'a", name_ru='Ичан-Кала', name_en='Ichan Kala (Inner Town)', description_uz="Xivaning eski shahri — Ichan Qal'a, UNESCO Jahon merosi ro'yxatiga kiritilgan. 10 metr balandlikdagi devor bilan o'ralgan bu hududda 50 dan ortiq tarixiy yodgorliklar va 250 dan ortiq qadimiy uylar mavjud. Kunjutko'ta minorasi, Pahlavon Mahmud maqbarasi va Kalta Minor kabi mashhur joylar shu yerda joylashgan.", description_ru='Старый город Хивы — Ичан-Кала, внесённый в список Всемирного наследия ЮНЕСКО. Эта территория, окружённая стенами высотой 10 метров, содержит более 50 исторических памятников и 250 древних домов. Здесь расположены знаменитые места: минарет Куня-Арк, мавзолей Пахлавана Махмуда и Калта-Минар.', description_en='The old town of Khiva — Ichan Kala, a UNESCO World Heritage Site. Surrounded by 10-meter-high walls, this area contains over 50 historic monuments and 250 ancient houses. Famous landmarks like the Kunya-Ark minaret, Pahlavon Mahmud mausoleum, and Kalta Minor are located here.', short_desc_uz='UNESCO Jahon merosi — Xivaning eski shahri', short_desc_ru='Всемирное наследие ЮНЕСКО — старый город Хивы', short_desc_en="UNESCO World Heritage — Khiva's old town", address_uz="Ichan Qal'a, Xiva", address_ru='Ичан-Кала, Хива', address_en='Ichan Kala, Khiva', city='Xiva', latitude=41.3775, longitude=60.3638, phone='+998623524400', website='https://ichankala.uz', telegram=None, instagram=None, image_url='/images/pilgrimage/ichan-kala.jpg', gallery_images='["/images/pilgrimage/ichan-kala-1.jpg", "/images/pilgrimage/ichan-kala-2.jpg", "/images/pilgrimage/ichan-kala-3.jpg"]', rating=4.8, review_count=1120, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "07:00-20:00"}', view_count=47000, historical_period='XVI asrdan', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgde002yjja2pi1tzf1c', place_type='PILGRIMAGE_SITE', name_uz='Xoja Daniyor maqbarasi', name_ru='Мавзолей Ходжа Данияр', name_en='Khoja Daniyar Mausoleum', description_uz="Xoja Daniyor (Poyg'ambar Dovud) maqbarasi — Samarqanddagi eng muqaddas ziyoratgohlardan biri. Afsonaga ko'ra, bu yerga Iso alayhissalom tomonidan olib kelingan. 18 metrlik qabr joylashgan. Musulmonlar, xristianlar va yahudiylar ziyorat qiladigan joy.", description_ru='Мавзолей Ходжа Данияра (пророка Давида) — одно из самых священных мест паломничества в Самарканде. По легенде, останки были принесены сюда Иисусом. Длина гробницы — 18 метров. Место паломничества мусульман, христиан и иудеев.', description_en='The Khoja Daniyar (Prophet Daniel) mausoleum — one of the holiest pilgrimage sites in Samarkand. According to legend, the remains were brought here by Jesus. The tomb is 18 meters long. A pilgrimage site for Muslims, Christians, and Jews.', short_desc_uz='Uch din ziyoratchilari tashrif buyuradigan muqaddas joy', short_desc_ru='Святое место для паломников трёх религий', short_desc_en='Sacred site for pilgrims of three faiths', address_uz="Xoja Daniyor ko'chasi, Samarqand", address_ru='улица Ходжа Данияр, Самарканд', address_en='Khoja Daniyar Street, Samarkand', city='Samarqand', latitude=39.647, longitude=66.953, phone='+998662342700', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/khoja-daniyar.jpg', gallery_images='[]', rating=4.7, review_count=980, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=42000, historical_period='Qadim zamon', owner_id=None, category_id='cmp7ewgbm0007jja2pnn47pqe'))
db.add(Place(id='cmp7ewgdf0030jja2t2bmor3x', place_type='PILGRIMAGE_SITE', name_uz='Chor Bakr nekropol', name_ru='Некрополь Чор Бакр', name_en='Chor Bakr Necropolis', description_uz="XVI asrda qurilgan Chor Bakr nekropol — Buxoroning eng muhim ziyoratgohlaridan biri. Abu Bakr Said va uning avlodlari dafn etilgan. O'rta Osiyo islom me'morchiligining noyob namunasi.", description_ru='Некрополь Чор Бакр, построенный в XVI веке — одно из важнейших мест паломничества Бухары. Здесь похоронены Абу Бакр Саид и его потомки. Уникальный пример исламской архитектуры Средней Азии.', description_en="The Chor Bakr Necropolis, built in the 16th century — one of Bukhara's most important pilgrimage sites. Abu Bakr Said and his descendants are buried here. A unique example of Central Asian Islamic architecture.", short_desc_uz='Buxoroning muhim ziyoratgoh nekropol', short_desc_ru='Важный паломнический некрополь Бухары', short_desc_en='Important pilgrimage necropolis of Bukhara', address_uz="Chor Bakr ko'chasi, Buxoro", address_ru='улица Чор Бакр, Бухара', address_en='Chor Bakr Street, Bukhara', city='Buxoro', latitude=39.808, longitude=64.424, phone='+998652256800', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/chor-bakr-necropolis.jpg', gallery_images='[]', rating=4.7, review_count=560, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=False, working_hours='{"all": "08:00-17:30"}', view_count=19000, historical_period='XVI asr', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgdf0032jja2aobqpla3', place_type='PILGRIMAGE_SITE', name_uz='Zangiota majmuasi', name_ru='Комплекс Зангиота', name_en='Zangiota Complex', description_uz="Toshkentdan 25 km uzoqlikda joylashgan Zangiota ziyoratgoh majmuasi. Zangiota ata va Zangiota onaning maqbaralari. O'zbekistonning eng ko'p tashrif buyuriladigan ziyoratgohlaridan biri.", description_ru='Паломнический комплекс Зангиота в 25 км от Ташкента. Мавзолеи Зангиота ата и Зангиота она. Одно из самых посещаемых мест паломничества в Узбекистане.', description_en='The Zangiota pilgrimage complex located 25 km from Tashkent. Tombs of Zangiota ata and Zangiota ona. One of the most visited pilgrimage sites in Uzbekistan.', short_desc_uz='Toshkent yaqinidagi mashhur ziyoratgoh', short_desc_ru='Известное место паломничества near Ташкента', short_desc_en='Famous pilgrimage site near Tashkent', address_uz="Zangiota qishlog'i, Toshkent viloyati", address_ru='посёлок Зангиота, Ташкентская область', address_en='Zangiota Village, Tashkent Region', city='Toshkent', latitude=41.38, longitude=69.15, phone='+998712700500', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/zangiota.jpg', gallery_images='[]', rating=4.7, review_count=890, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=32000, historical_period='XIV-XIX asrlar', owner_id=None, category_id='cmp7ewgbm0007jja2pnn47pqe'))
db.add(Place(id='cmp7ewgdg0034jja20ac0k6fu', place_type='PILGRIMAGE_SITE', name_uz='Juma masjidi (Xiva)', name_ru='Джума-мечеть (Хива)', name_en='Juma Mosque (Khiva)', description_uz="Xiva Ichan Qal'adagi Juma masjidi — 1788-1789 yillarda qurilgan. 212 ta yog'och ustunlari bilan ajralib turadi, ulardan ba'zilari IX-X asrlarga oid qadimiy masjidlardan olib kelingan. O'rta Osiyo islom me'morchiligining noyob namunasi.", description_ru='Джума-мечеть в Ичан-Кале Хивы — построена в 1788-1789 годах. Выделяется 212 деревянными колоннами, некоторые из которых привезены из древних мечетей IX-X веков. Уникальный пример исламской архитектуры Средней Азии.', description_en="The Juma Mosque in Khiva's Ichan Kala — built in 1788–1789. Features 212 wooden columns, some brought from ancient mosques dating back to the 9th–10th centuries. A unique example of Central Asian Islamic architecture.", short_desc_uz="212 yog'och ustunli qadimiy masjid", short_desc_ru='Древняя мечеть с 212 деревянными колоннами', short_desc_en='Ancient mosque with 212 wooden columns', address_uz="Ichan Qal'a, Xiva", address_ru='Ичан-Кала, Хива', address_en='Ichan Kala, Khiva', city='Xiva', latitude=41.3768, longitude=60.3632, phone=None, website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/juma-mosque-khiva.jpg', gallery_images='["/images/pilgrimage/juma-mosque-khiva-1.jpg"]', rating=4.7, review_count=760, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=31000, historical_period='1788-1789 yillar', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdg0036jja245swhq0q', place_type='PILGRIMAGE_SITE', name_uz='Poi Kalon majmuasi', name_ru='Комплекс Пои Калон', name_en='Poi Kalon Complex', description_uz="Buxoroning eng mashhur me'moriy ansambli — Kalyon minorasi, Mir-i Arab madrasasi va Masjid-i Kalon. 1127-yilda qurilgan Kalyon minorasi 47 metr balandlikda. O'rta Osiyo me'morchiligining durdonasi.", description_ru='Самый известный архитектурный ансамбль Бухары — минарет Калян, медресе Мири Араб и мечеть Калян. Минарет Калян, построенный в 1127 году, высотой 47 метров. Жемчужина среднеазиатской архитектуры.', description_en="Bukhara's most famous architectural ensemble — Kalyon Minaret, Mir-i Arab Madrasah, and Kalon Mosque. The Kalyon Minaret, built in 1127, stands 47 meters tall. A jewel of Central Asian architecture.", short_desc_uz='Buxoro simvoli — Kalyon minorasi majmuasi', short_desc_ru='Символ Бухары — комплекс минарета Калян', short_desc_en='Bukhara symbol — Kalyon Minaret complex', address_uz='Poi Kalon maydoni, Buxoro', address_ru='Площадь Пои Калон, Бухара', address_en='Poi Kalon Square, Bukhara', city='Buxoro', latitude=39.7748, longitude=64.4255, phone='+998652254600', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/poi-kalon.jpg', gallery_images='["/images/pilgrimage/poi-kalon-1.jpg", "/images/pilgrimage/poi-kalon-2.jpg"]', rating=4.9, review_count=1560, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=56000, historical_period='XII-XVI asrlar', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdh0038jja2d51wiokb', place_type='PILGRIMAGE_SITE', name_uz='Toshkent Minor masjidi', name_ru='Мечеть Минор в Ташкенте', name_en='Minor Mosque Tashkent', description_uz="Toshkent markazida joylashgan yangi va chiroyli masjid. Oq marmar va ko'k gumbazli zamonaviy me'morchilik. 2014-yilda ochilgan bo'lib, o'zbek milliy bezaklar bilan bezatilgan.", description_ru='Новая и красивая мечеть в центре Ташкента. Современная архитектура из белого мрамора с голубым куполом. Открыта в 2014 году, украшена национальными узбекскими орнаментами.', description_en='A new and beautiful mosque in central Tashkent. Modern architecture of white marble with a blue dome. Opened in 2014, decorated with Uzbek national ornaments.', short_desc_uz='Toshkent markazidagi chiroyli yangi masjid', short_desc_ru='Красивая новая мечеть в центре Ташкента', short_desc_en='Beautiful new mosque in central Tashkent', address_uz="Amir Temur shoh ko'chasi, Toshkent", address_ru='проспект Амира Тимура, Ташкент', address_en='Amir Temur Avenue, Tashkent', city='Toshkent', latitude=41.3015, longitude=69.243, phone='+998712700600', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/minor-mosque-tashkent.jpg', gallery_images='[]', rating=4.6, review_count=560, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=False, working_hours='{"all": "06:00-21:00"}', view_count=28000, historical_period='2014 yil', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdh003ajja2sda4mhkx', place_type='PILGRIMAGE_SITE', name_uz='Kalta Minor', name_ru='Калта-Минар', name_en='Kalta Minor', description_uz="Xivadagi Kalta Minor — 1855-yilda qurilgan, ammo tugallanmagan qolgan minor. 26 metr balandligi va kengligi bilan ajralib turadi. O'zbekistonning eng taniqli me'moriy yodgorliklaridan biri. Barcha sirlari bilan qoplangan go'zal bezaklari.", description_ru='Калта-Минар в Хиве — минарет, построенный в 1855 году, но так и не завершённый. Выделяется высотой 26 метров и шириной. Один из самых узнаваемых архитектурных памятников Узбекистана. Красивые изразцовые украшения.', description_en="Kalta Minor in Khiva — a minaret built in 1855 but never completed. Distinguished by its 26-meter height and unusual width. One of Uzbekistan's most recognizable landmarks. Beautiful tile decorations.", short_desc_uz='Tugallanmagan minora — Xivaning ramzi', short_desc_ru='Незавершённый минарет — символ Хивы', short_desc_en='Unfinished minaret — symbol of Khiva', address_uz="Ichan Qal'a, Xiva", address_ru='Ичан-Кала, Хива', address_en='Ichan Kala, Khiva', city='Xiva', latitude=41.376, longitude=60.3645, phone=None, website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/kalta-minor.jpg', gallery_images='["/images/pilgrimage/kalta-minor-1.jpg"]', rating=4.6, review_count=680, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "07:00-20:00"}', view_count=25000, historical_period='1855 yil', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdi003cjja2kc80u5kw', place_type='PILGRIMAGE_SITE', name_uz='Pahlavon Mahmud maqbarasi', name_ru='Мавзолей Пахлавана Махмуда', name_en='Pahlavon Mahmud Mausoleum', description_uz='Xivaning homiy avliyosi Pahlavon Mahmud (1247-1326) maqbarasi. Shoir, mahoratli kurashchi va avliyo sifatida hurmat qilinadi. Xiva xonlari bu yerga dafn etilgan. Moviy koshinlari bilan bezatilgan ajoyib inshoot.', description_ru='Мавзолей покровителя Хивы Пахлавана Махмуда (1247-1326). Уважаем как поэт, искусный борец и святой. Хивинские ханы похоронены здесь. Потрясающее сооружение, украшенное голубыми изразцами.', description_en="The mausoleum of Khiva's patron saint Pahlavon Mahmud (1247-1326). Revered as a poet, skilled wrestler, and saint. Khiva khans are buried here. A stunning building adorned with blue tiles.", short_desc_uz='Xiva homiy avliyosining maqbarasi', short_desc_ru='Мавзолей покровителя Хивы', short_desc_en="Mausoleum of Khiva's patron saint", address_uz="Ichan Qal'a, Pahlavon Mahmud ko'chasi, Xiva", address_ru='Ичан-Кала, улица Пахлавана Махмуда, Хива', address_en='Ichan Kala, Pahlavon Mahmud Street, Khiva', city='Xiva', latitude=41.3772, longitude=60.3635, phone=None, website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/pahlavon-mahmud.jpg', gallery_images='["/images/pilgrimage/pahlavon-mahmud-1.jpg"]', rating=4.8, review_count=720, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=29000, historical_period='XIV asr — 1913 yil', owner_id=None, category_id='cmp7ewgbm0007jja2pnn47pqe'))
db.add(Place(id='cmp7ewgdi003ejja20s3iq0cq', place_type='PILGRIMAGE_SITE', name_uz='Hast Imam majmuasi', name_ru='Комплекс Хаст-Имам', name_en='Hast Imam Complex', description_uz="Toshkentdagi eng muhim islomiy majmua. Xazrat Imom jome masjidi, Muyi Muborak madrasasi va Baroq-Xon madrasasi joylashgan. Qur'onning eng qadimiy nusxasi — Uthmon Qur'oni shu yerda saqlanadi. O'zbekistonning bosh muftiysi qarorgohi.", description_ru='Самый важный исламский комплекс в Ташкенте. Здесь расположены соборная мечеть Хазрат Имам, медресе Муйи Мубарак и медресе Барак-Хан. Здесь хранится самая древняя копия Корана — Османовский Коран. Резиденция главного муфтия Узбекистана.', description_en='The most important Islamic complex in Tashkent. Home to the Hazrat Imam congregational mosque, Muyi Mubarak madrasah, and Barak-Khan madrasah. The oldest copy of the Quran — the Uthman Quran — is preserved here. Residence of the Grand Mufti of Uzbekistan.', short_desc_uz='Toshkentdagi eng muhim islomiy markaz', short_desc_ru='Самый важный исламский центр Ташкента', short_desc_en='The most important Islamic center in Tashkent', address_uz="Hast Imam ko'chasi, Toshkent", address_ru='улица Хаст-Имам, Ташкент', address_en='Hast Imam Street, Tashkent', city='Toshkent', latitude=41.2856, longitude=69.2772, phone='+998712456789', website='https://hastimam.uz', telegram=None, instagram=None, image_url='/images/pilgrimage/hast-imam.jpg', gallery_images='["/images/pilgrimage/hast-imam-1.jpg", "/images/pilgrimage/hast-imam-2.jpg"]', rating=4.8, review_count=1450, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "09:00-18:00"}', view_count=58000, historical_period='XVI asr', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgdj003gjja23xkrw3iv', place_type='PILGRIMAGE_SITE', name_uz='Buxoro Arki', name_ru='Бухарская Арк', name_en='Bukhara Ark (Citadel)', description_uz="Buxoroning eng qadimiy inshooti — Ark qal'asi. V asrdan beri mavjud bo'lib, Buxoro xonlarining rasmiy qarorgohi bo'lgan. Qal'a ichida masjidlar, hovlilar va hukumat binolari joylashgan. Shaharning eng baland nuqtasi bo'lib, atrofning go'zal manzarasi ochiladi.", description_ru='Самое древнее сооружение Бухары — цитадель Арк. Существует с V века, была официальной резиденцией бухарских ханов. Внутри цитадели расположены мечети, дворцы и правительственные здания. Высочайшая точка города с прекрасным видом на окрестности.', description_en="The oldest structure in Bukhara — the Ark citadel. Existing since the 5th century, it served as the official residence of Bukhara's khans. The citadel houses mosques, palaces, and government buildings. The highest point in the city with a beautiful view of the surroundings.", short_desc_uz='Buxoro xonlarining qadimiy qarorgohi', short_desc_ru='Древняя резиденция бухарских ханов', short_desc_en="Ancient residence of Bukhara's khans", address_uz='Ark maydoni, Buxoro', address_ru='Площадь Арк, Бухара', address_en='Ark Square, Bukhara', city='Buxoro', latitude=39.7746, longitude=64.4286, phone='+998652247700', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/bukhara-ark.jpg', gallery_images='["/images/pilgrimage/bukhara-ark-1.jpg", "/images/pilgrimage/bukhara-ark-2.jpg"]', rating=4.6, review_count=980, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "09:00-17:00"}', view_count=43000, historical_period='V asrdan', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgdj003ijja2xvygpy9w', place_type='PILGRIMAGE_SITE', name_uz='Sitorai Moxi Xosa saroyi', name_ru='Дворец Ситораи Мохи Хоса', name_en='Sitorai Mokhi Khosa Palace', description_uz="Buxoro amirlari yozgi saroyi — Sitorai Moxi Xosa (Yulduzlar yulduzi). XIX asr oxirida qurilgan bu saroy O'rta Osiyo va Yevropa uslublarining uyg'unligi. Ajoyib bog'lar va hovuzlar bilan.", description_ru='Летний дворец бухарских эмиров — Ситораи Мохи Хоса (Звезда и полумесяц). Построен в конце XIX века, сочетает среднеазиатский и европейский стили. Прекрасные сады и бассейны.', description_en='The summer palace of Bukhara emirs — Sitorai Mokhi Khosa (Star and Crescent). Built in the late 19th century, blending Central Asian and European styles. Beautiful gardens and pools.', short_desc_uz='Buxoro amirlarining yozgi saroyi', short_desc_ru='Летний дворец бухарских эмиров', short_desc_en='Summer palace of Bukhara emirs', address_uz="Sitorai Moxi Xosa ko'chasi, Buxoro", address_ru='улица Ситораи Мохи Хоса, Бухара', address_en='Sitorai Mokhi Khosa Street, Bukhara', city='Buxoro', latitude=39.78, longitude=64.435, phone='+998652255700', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/sitorai-mokhi-khosa.jpg', gallery_images='[]', rating=4.6, review_count=670, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=False, working_hours='{"all": "09:00-17:00"}', view_count=24000, historical_period='XIX asr oxiri', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgdk003kjja2k5734cbt', place_type='PILGRIMAGE_SITE', name_uz='Bibixonim jome masjidi', name_ru='Мечеть Биби-Ханум', name_en='Bibi-Khanum Mosque', description_uz="Amir Temur rafiqasi Bibixonim buyrug'i bilan 1399-1404 yillarda qurilgan jome masjid. O'sha davrda dunyodagi eng katta masjidlardan biri bo'lgan. 1897 yildagi zilzila natijasida buzilib, keyinchalik qayta tiklangan. Bibi Maryam nomi bilan atalgan bu masjid islom me'morchiligining nodir namunasidir.", description_ru='Главная мечеть, построенная по приказу жены Амира Тимура Биби-Ханум в 1399-1404 годах. Была одной из крупнейших мечетей в мире того времени. Разрушена землетрясением 1897 года и впоследствии восстановлена. Названная в честь Марии, эта мечеть является редким образцом исламской архитектуры.', description_en="A congregational mosque built by order of Amir Timur's wife Bibi-Khanum between 1399–1404. Once one of the largest mosques in the world. Destroyed by an earthquake in 1897 and later restored. Named after Bibi Maryam, this mosque is a rare example of Islamic architecture.", short_desc_uz='Amir Temur davrining eng katta masjidi', short_desc_ru='Крупнейшая мечеть эпохи Амира Тимура', short_desc_en="The largest mosque of Amir Timur's era", address_uz="Bibixonim ko'chasi, Samarqand", address_ru='улица Биби-Ханум, Самарканд', address_en='Bibi-Khanum Street, Samarkand', city='Samarqand', latitude=39.6556, longitude=66.9649, phone='+998662336100', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/bibi-khanum.jpg', gallery_images='["/images/pilgrimage/bibi-khanum-1.jpg", "/images/pilgrimage/bibi-khanum-2.jpg"]', rating=4.7, review_count=1230, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "08:00-18:00"}', view_count=56000, historical_period='1399-1404 yillar', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdl003mjja2mb9ccg0t', place_type='PILGRIMAGE_SITE', name_uz='Chor Minor', name_ru='Чор-Минор', name_en='Chor Minor (Four Minarets)', description_uz='XVIII asr oxirida qurilgan noyob me\'moriy yodgorlik. To\'rt gumbazli minorasi bilan dunyoda yagona inshoot. Xalq orasida "To\'rt minorali darvoza" nomi bilan mashhur. Buxoroning ramzi bo\'lib, ko\'plab sayohatchilarni jalb qiladi. Har bir minorada Qur\'on oyatlari bitilgan koshinlar mavjud.', description_ru='Уникальный архитектурный памятник, построенный в конце XVIII века. Единственное в мире сооружение с четырьмя купольными минаретами. В народе известно как "Ворота с четырьмя минаретами". Символ Бухары, привлекающий множество путешественников. Каждый минарет украшен изразцами с аятами Корана.', description_en='A unique architectural monument built in the late 18th century. The only structure in the world with four domed minarets. Popularly known as the "Gate of Four Minarets." A symbol of Bukhara that attracts many travelers. Each minaret features tiles inscribed with Quranic verses.', short_desc_uz="To'rt minorali noyob me'moriy yodgorlik", short_desc_ru='Уникальный памятник с четырьмя минаретами', short_desc_en='Unique monument with four minarets', address_uz="Chor Minor ko'chasi, Buxoro", address_ru='улица Чор-Минор, Бухара', address_en='Chor Minor Street, Bukhara', city='Buxoro', latitude=39.7758, longitude=64.4166, phone=None, website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/chor-minor.jpg', gallery_images='["/images/pilgrimage/chor-minor-1.jpg"]', rating=4.5, review_count=870, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "09:00-18:00"}', view_count=38000, historical_period='XVIII asr oxiri', owner_id=None, category_id='cmp7ewgbm0004jja2tetb4811'))
db.add(Place(id='cmp7ewgdl003ojja2g4kt7urc', place_type='PILGRIMAGE_SITE', name_uz='Ulugbek rasadxonasi', name_ru='Обсерватория Улугбека', name_en='Ulugbek Observatory', description_uz="Mirzo Ulugbek tomonidan 1424-1429 yillarda qurilgan astronomik rasadxona. O'rta Osiyoda birinchi va dunyoda eng qadimiy rasadxonalardan biri. Ulugbek yulduzlar jadvali shu yerda tuzilgan bo'lib, ilm-fan tarixida muhim ahamiyatga ega. 1908 yilda rus arxeologi Vyatkin tomonidan qayta kashf etilgan.", description_ru='Астрономическая обсерватория, построенная Мирзо Улугбеком в 1424-1429 годах. Первая в Средней Азии и одна из старейших в мире. Здесь составлена звёздная таблица Улугбека, имеющая важное значение в истории науки. Заново открыта в 1908 году русским археологом Вяткиным.', description_en="An astronomical observatory built by Mirzo Ulugbek in 1424–1429. The first in Central Asia and one of the oldest in the world. Ulugbek's star catalog was compiled here, of great importance in the history of science. Rediscovered in 1908 by Russian archaeologist Vyatkin.", short_desc_uz='Ulugbekning qadimiy astronomik rasadxonasi', short_desc_ru='Древняя астрономическая обсерватория Улугбека', short_desc_en="Ulugbek's ancient astronomical observatory", address_uz="Ulugbek ko'chasi, Samarqand", address_ru='улица Улугбека, Самарканд', address_en='Ulugbek Street, Samarkand', city='Samarqand', latitude=39.6615, longitude=66.984, phone='+998662337100', website=None, telegram=None, instagram=None, image_url='/images/pilgrimage/ulugbek-observatory.jpg', gallery_images='["/images/pilgrimage/ulugbek-observatory-1.jpg", "/images/pilgrimage/ulugbek-observatory-2.jpg"]', rating=4.6, review_count=890, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "09:00-17:00"}', view_count=35000, historical_period='1424-1429 yillar', owner_id=None, category_id='cmp7ewgbq000fjja2szk35etr'))
db.add(Place(id='cmp7ewgdr003tjja23fef6oht', place_type='SHOP', name_uz='Samarqand Suvenirlari', name_ru='Сувениры Самарканда', name_en='Samarkand Souvenirs', description_uz="Samarqandning eng yirik suvenir do'koni. Qo'lda ishlangan keramika, ipak buyumlar, zargarlik buyumlari va boshqa an'anaviy o'zbek san'ati mahsulotlari. Har bir buyum o'zbek hunarmandlari tomonidan qo'lda yasalgan.", description_ru='Крупнейший сувенирный магазин Самарканда. Ручная керамика, шёлковые изделия, ювелирные украшения и другие изделия традиционного узбекского искусства. Каждый предмет изготовлен вручную узбекскими мастерами.', description_en='The largest souvenir shop in Samarkand. Handmade ceramics, silk products, jewelry, and other traditional Uzbek art products. Each item is handcrafted by Uzbek artisans.', short_desc_uz="Qo'lda ishlangan o'zbek suvenirlari", short_desc_ru='Ручные узбекские сувениры', short_desc_en='Handmade Uzbek souvenirs', address_uz='Registon maydoni yonida, Samarqand', address_ru='Рядом с площадью Регистан, Самарканд', address_en='Next to Registan Square, Samarkand', city='Samarqand', latitude=39.6552, longitude=66.9585, phone='+998662338800', website=None, telegram='@samarksouvenirs', instagram=None, image_url=None, gallery_images='[]', rating=4.4, review_count=234, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-20:00"}', view_count=8900, historical_period=None, owner_id=None, category_id='cmp7ewgbo000ajja2ydxykjb7'))
db.add(Place(id='cmp7ewgdr003ujja2cty5n00j', place_type='SHOP', name_uz="Marg'ilon Ipak Do'koni", name_ru='Магазин шёлка Маргилан', name_en='Margilan Silk Shop', description_uz="Marg'ilon ipaklari bilan mashhur do'kon. O'zbekistonning eng yaxshi ipak fabrikalari bilan hamkorlikda faoliyat yuritadi. Atlas, adras, banoras va boshqa ipak matolar. Qo'lda bo'yash an'anaviy usullari qo'llaniladi.", description_ru='Магазин, известный маргиланским шёлком. Работает в сотрудничестве с лучшими шёлковыми фабриками Узбекистана. Атлас, адрас, бенарас и другие шёлковые ткани. Применяются традиционные методы ручной окраски.', description_en='A shop famous for Margilan silk. Works in partnership with the best silk factories in Uzbekistan. Atlas, adras, benares, and other silk fabrics. Traditional hand-dyeing methods are used.', short_desc_uz="Marg'ilon ipaklari va an'anaviy matolar", short_desc_ru='Маргиланский шёлк и традиционные ткани', short_desc_en='Margilan silk and traditional fabrics', address_uz="Ichan Qal'a, Buxoro", address_ru='Ичан-Кала, Бухара', address_en='Ichan Kala, Bukhara', city='Buxoro', latitude=39.7762, longitude=64.4256, phone='+998652249900', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.6, review_count=178, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-19:00"}', view_count=6200, historical_period=None, owner_id=None, category_id='cmp7ewgbo000cjja2epdk1nrx'))
db.add(Place(id='cmp7ewgdr003vjja2rinrsj8o', place_type='SHOP', name_uz="O'zbekiston Hunarmandlari", name_ru='Мастера Узбекистана', name_en='Uzbekistan Crafts', description_uz="Toshkentdagi eng yirik hunarmandchilik markazi. Butun O'zbekiston bo'ylab ustalar tomonidan tayyorlangan qo'l mehnati mahsulotlari. Pichoqlar (Mang'it pichoqlari), gilamlar, zargarlik buyumlari va musiqa asboblari.", description_ru='Крупнейший центр ремесел в Ташкенте. Изделия ручной работы мастеров со всего Узбекистана. Ножи (мангитские ножи), ковры, ювелирные изделия и музыкальные инструменты.', description_en='The largest crafts center in Tashkent. Handmade products by artisans from all over Uzbekistan. Knives (Manghit knives), carpets, jewelry, and musical instruments.', short_desc_uz="Butun O'zbekiston hunarmandchilari mahsulotlari", short_desc_ru='Изделия ремесленников со всего Узбекистана', short_desc_en='Handicrafts from all over Uzbekistan', address_uz="Sayilgoh ko'chasi, 5, Toshkent", address_ru='улица Сайилгох, 5, Ташкент', address_en='Sayilgoh Street, 5, Tashkent', city='Toshkent', latitude=41.2935, longitude=69.2658, phone='+998712567890', website=None, telegram=None, instagram='@uzcrafts', image_url=None, gallery_images='[]', rating=4.3, review_count=287, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-20:00"}', view_count=11200, historical_period=None, owner_id=None, category_id='cmp7ewgbo000ajja2ydxykjb7'))
db.add(Place(id='cmp7ewgdr003wjja29xsz8cju', place_type='SHOP', name_uz="Samarqand Gilam Do'koni", name_ru='Ковровый магазин Самарканд', name_en='Samarkand Carpet Shop', description_uz="Samarqandning eng yaxshi gilamlarini taklif etadigan do'kon. Qo'lda to'qilgan o'zbek gilamlari — turli o'lcham va naqshlarda. Har bir gilam xususiy hikoyaga ega.", description_ru='Магазин лучших ковров Самарканда. Ручные узбекские ковры — различных размеров и узоров. Каждый ковёр имеет свою уникальную историю.', description_en='A shop offering the finest Samarkand carpets. Hand-woven Uzbek carpets in various sizes and patterns. Each carpet has its own unique story.', short_desc_uz="Qo'lda to'qilgan o'zbek gilamlari", short_desc_ru='Ручные узбекские ковры', short_desc_en='Hand-woven Uzbek carpets', address_uz="Registon ko'chasi, 18, Samarqand", address_ru='улица Регистан, 18, Самарканд', address_en='Registon Street, 18, Samarkand', city='Samarqand', latitude=39.656, longitude=66.957, phone='+998662343800', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.5, review_count=167, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-19:00"}', view_count=6500, historical_period=None, owner_id=None, category_id='cmp7ewgbo000cjja2epdk1nrx'))
db.add(Place(id='cmp7ewgdt003yjja2g97o1ohq', place_type='SHOP', name_uz='Samarqand Oltin Zargarlik', name_ru='Самаркандское Ювелирное Золотое', name_en='Samarkand Gold Jewelry', description_uz="O'zbekistonning an'anaviy zargarlik san'ati — Samarqand Oltin Zargarlik do'koni. Oltin, kumush va qimmatbaho toshlardan qo'lda yasalgan buyumlar. Nikoh va sovg'a uchun ideal.", description_ru='Традиционное ювелирное искусство Узбекистана — магазин Самаркандское Золотое Ювелирное. Ручные изделия из золота, серебра и драгоценных камней. Идеально для свадьбы и подарков.', description_en='Traditional Uzbek jewelry art — Samarkand Gold Jewelry shop. Handmade items from gold, silver, and precious stones. Ideal for weddings and gifts.', short_desc_uz='Oltin va kumush zargarlik buyumlari', short_desc_ru='Ювелирные изделия из золота и серебра', short_desc_en='Gold and silver jewelry', address_uz="Bunyodkor ko'chasi, 22, Samarqand", address_ru='улица Бунёдкор, 22, Самарканд', address_en='Bunyodkor Street, 22, Samarkand', city='Samarqand', latitude=39.651, longitude=66.958, phone='+998662344900', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.6, review_count=134, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "10:00-19:00"}', view_count=5200, historical_period=None, owner_id=None, category_id='cmp7ewgbn0009jja2eaahp1k6'))
db.add(Place(id='cmp7ewgdu0040jja2ik1vs8dm', place_type='SHOP', name_uz='Buxoro Suvenir Markazi', name_ru='Сувенирный центр Бухары', name_en='Bukhara Souvenir Center', description_uz="Buxoro eski shahridagi eng katta suvenir markazi. Buxoro suvenirlari — miniatyuralar, sopol buyumlar, ipak va boshqa xotiralik. Bepul o'rash va xalqaro yetkazib berish.", description_ru='Крупнейший сувенирный центр в старом городе Бухары. Бухарские сувениры — миниатюры, керамика, шёлк и другие памятные вещи. Бесплатная упаковка и международная доставка.', description_en='The largest souvenir center in Bukhara old town. Bukhara souvenirs — miniatures, ceramics, silk, and other mementos. Free wrapping and international delivery.', short_desc_uz='Buxoro eski shahridagi eng katta suvenir markazi', short_desc_ru='Крупнейший сувенирный центр старого города Бухары', short_desc_en='Largest souvenir center in Bukhara old town', address_uz="Sayohat ko'chasi, 1, Buxoro", address_ru='улица Саяхат, 1, Бухара', address_en='Sayohat Street, 1, Bukhara', city='Buxoro', latitude=39.778, longitude=64.422, phone='+998652259100', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.3, review_count=145, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "08:00-20:00"}', view_count=5600, historical_period=None, owner_id=None, category_id='cmp7ewgbo000ajja2ydxykjb7'))
db.add(Place(id='cmp7ewgdu0042jja24qfhmu6b', place_type='SHOP', name_uz='Toshkent City Mall', name_ru='Ташкент Сити Молл', name_en='Tashkent City Mall', description_uz='Poytaxtdagi eng yirik savdo markazi. Xalqaro va mahalliy brendlar, oziq-ovqat korti, kinoteatr va bolalar maydonchasi. Bir joyda hamma narsa — xarid qilish va dam olish.', description_ru='Крупнейший торговый центр столицы. Международные и местные бренды, фудкорт, кинотеатр и детская площадка. Всё в одном месте — шопинг и отдых.', description_en='The largest shopping mall in the capital. International and local brands, food court, cinema, and playground. Everything in one place — shopping and leisure.', short_desc_uz='Poytaxtdagi eng yirik savdo markazi', short_desc_ru='Крупнейший торговый центр столицы', short_desc_en='The largest shopping mall in the capital', address_uz="Amir Temur shoh ko'chasi, 107, Toshkent", address_ru='проспект Амира Тимура, 107, Ташкент', address_en='Amir Temur Avenue, 107, Tashkent', city='Toshkent', latitude=41.3, longitude=69.238, phone='+998712700700', website='https://tashkentcitymall.uz', telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.4, review_count=567, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "10:00-22:00"}', view_count=18900, historical_period=None, owner_id=None, category_id='cmp7ewgbn0009jja2eaahp1k6'))
