db.add(Place(id='cmp7ewgdv0046jja2p80tlaer', place_type='SHOP', name_uz="Rishton Kulolchilik Do'koni", name_ru='Гончарный магазин Риштан', name_en='Rishtan Pottery Shop', description_uz="Rishtan — O'zbekistonning kulolchilik markazi. Bu do'konda faqat Rishtan usta-kulollarining qo'lda ishlangan sopol buyumlari namoyish etiladi. Ko'k rangli an'anaviy naqshlar bilan bezatilgan laganlar, piyola va boshqa sopol idishlar.", description_ru='Риштан — центр гончарного искусства Узбекистана. В этом магазине представлены только ручные керамические изделия мастеров Риштана. Тарелки, пиалы и другая керамическая посуда с традиционным синим орнаментом.', description_en='Rishtan — the pottery center of Uzbekistan. This shop displays only handmade ceramic works by Rishtan master potters. Plates, bowls, and other ceramic ware with traditional blue patterns.', short_desc_uz="Rishtan kulollari — qo'lda ishlangan sopol", short_desc_ru='Риштанская керамика — ручная работа', short_desc_en='Rishtan pottery — handmade ceramics', address_uz="Sayohat ko'chasi, 22, Xiva", address_ru='улица Саяхат, 22, Хива', address_en='Sayohat Street, 22, Khiva', city='Xiva', latitude=41.3762, longitude=60.365, phone='+998623526600', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.5, review_count=156, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-18:00"}', view_count=4500, historical_period=None, owner_id=None, category_id='cmp7ewgbo000ajja2ydxykjb7'))
