db.add(Place(id='cmp7ewge5004kjja20qya6l3q', place_type='ATTRACTION', name_uz='Savdo gumbazlari', name_ru='Торговые купола', name_en='Trading Domes of Bukhara', description_uz="Buxoroning XVI asr savdo gumbazlari — Toqi Sarrafon, Toqi Telpakfurushon va Toqi Mulla. O'rta Osiyo savdo yo'llarining muhim markazi bo'lgan. Hozirda hunarmandchilik va savdo markazi sifatida faoliyat yuritadi. Tarixiy atmosfera saqlanib qolgan.", description_ru='Торговые купола Бухары XVI века — Токи Саррафон, Токи Телпакфурушон и Токи Мулла. Были важным центром среднеазиатских торговых путей. Сейчас действуют как ремесленный и торговый центр. Историческая атмосфера сохранена.', description_en='The 16th-century Trading Domes of Bukhara — Toqi Sarrafon, Toqi Telpakfurushon, and Toqi Mulla. Once an important center of Central Asian trade routes. Now functioning as a crafts and trade center. The historical atmosphere has been preserved.', short_desc_uz='XVI asr Buxoro savdo markazi', short_desc_ru='Торговый центр Бухары XVI века', short_desc_en='Bukhara 16th-century trading center', address_uz='Markaz, Buxoro', address_ru='Центр, Бухара', address_en='Center, Bukhara', city='Buxoro', latitude=39.7749, longitude=64.421, phone=None, website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.6, review_count=670, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-19:00"}', view_count=28000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge5004ljja2n7qqdubk', place_type='ATTRACTION', name_uz='Siyob bozori', name_ru='Сиобский базар', name_en='Siyob Bazaar', description_uz="Samarqanddagi eng yirik va eng qadimiy bozor. Mahsulotlarning keng tanlovi: mevalar, sabzavotlar, ziravorlar, go'sht va non. O'zbek bozor madaniyatini his qilish uchun eng yaxshi joy. Mahalliy aholi va sayohatchilar uchun teng muhim.", description_ru='Крупнейший и старейший базар в Самарканде. Широкий выбор продуктов: фрукты, овощи, специи, мясо и хлеб. Лучшее место для знакомства с культурой узбекского базара. Одинаково важен для местных жителей и путешественников.', description_en='The largest and oldest bazaar in Samarkand. A wide selection of produce: fruits, vegetables, spices, meat, and bread. The best place to experience Uzbek bazaar culture. Equally important for locals and travelers.', short_desc_uz='Samarqandning eng qadimiy va yirik bozori', short_desc_ru='Старейший и крупнейший базар Самарканда', short_desc_en='The oldest and largest bazaar in Samarkand', address_uz='Siyob bozori, Samarqand', address_ru='Сиобский базар, Самарканд', address_en='Siyob Bazaar, Samarkand', city='Samarqand', latitude=39.6589, longitude=66.9657, phone='+998662339900', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.5, review_count=890, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=False, working_hours='{"all": "06:00-18:00"}', view_count=34000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000ejja2p9vaa8lm'))
db.add(Place(id='cmp7ewge5004mjja262j9499n', place_type='ATTRACTION', name_uz='Chorsu bozori', name_ru='Чорсу базар', name_en='Chorsu Bazaar', description_uz="Toshkentdagi eng qadimiy va eng yirik bozor. Yashil gumbazli katta binosi bilan ajralib turadi. Mevalar, sabzavotlar, go'sht, non, ziravorlar va kiyim-kechaklar. O'zbekistonning haqiqiy lazzatlarini topish uchun eng yaxshi joy.", description_ru='Самый старый и крупный базар в Ташкенте. Выделяется большим зданием с зелёным куполом. Фрукты, овощи, мясо, хлеб, специи и одежда. Лучшее место для поиска настоящих вкусов Узбекистана.', description_en='The oldest and largest bazaar in Tashkent. Features a large green-domed building. Fruits, vegetables, meat, bread, spices, and clothing. The best place to discover the authentic flavors of Uzbekistan.', short_desc_uz="Toshkentning eng yirik an'anaviy bozori", short_desc_ru='Крупнейший традиционный базар Ташкента', short_desc_en="Tashkent's largest traditional bazaar", address_uz='Chorsu maydoni, Toshkent', address_ru='Площадь Чорсу, Ташкент', address_en='Chorsu Square, Tashkent', city='Toshkent', latitude=41.2974, longitude=69.2328, phone='+998712678901', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.4, review_count=1230, price_from=None, price_to=None, currency='UZS', is_halal=True, is_featured=True, working_hours='{"all": "06:00-18:00"}', view_count=45000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000ejja2p9vaa8lm'))
db.add(Place(id='cmp7ewge6004pjja21viip8su', place_type='ATTRACTION', name_uz='Afrasiyob qadimiy shahri', name_ru='Древний город Афрасиаб', name_en='Afrasiyab Ancient City', description_uz="Samarqandning qadimiy aholi punkti — Afrasiyob. Miloddan avval VII asrdan XIII asrgacha mavjud bo'lgan. Qazishmalar natijasida devor rasmlari, sopol buyumlar va tangalar topilgan. Afrasiyob muzeyida qadimiy ashyolar namoyish etiladi.", description_ru='Древнее поселение Самарканда — Афрасиаб. Существовало с VII века до н.э. до XIII века. В результате раскопок найдены настенные росписи, керамика и монеты. В музее Афрасиаба выставлены древние артефакты.', description_en='The ancient settlement of Samarkand — Afrasiyab. Existed from the 7th century BC to the 13th century AD. Excavations have revealed wall paintings, pottery, and coins. Ancient artifacts are displayed in the Afrasiyab Museum.', short_desc_uz='Samarqandning 2500 yillik qadimiy shahri', short_desc_ru='Древний город Самарканда возрастом 2500 лет', short_desc_en="Samarkand's 2500-year-old ancient city", address_uz="Afrasiyob ko'chasi, Samarqand", address_ru='улица Афрасиаб, Самарканд', address_en='Afrasiyab Street, Samarkand', city='Samarqand', latitude=39.6606, longitude=66.9559, phone='+998662330200', website='https://afrasiyab-museum.uz', telegram=None, instagram=None, image_url='/images/attractions/afrasiyab.jpg', gallery_images='["/images/attractions/afrasiyab-1.jpg", "/images/attractions/afrasiyab-2.jpg"]', rating=4.5, review_count=560, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-17:00"}', view_count=23000, historical_period='Miloddan avval VII asr — XIII asr', owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge6004qjja2ccm51ctf', place_type='ATTRACTION', name_uz="Konigil qishlog'i — Qog'oz tayyorlash", name_ru='Посёлок Конигиль — Изготовление бумаги', name_en='Konigil Village — Paper Making', description_uz="Samarqanddan 10 km uzoqlikdagi Konigil qishlog'i — qadimiy qog'oz tayyorlash markazi. Mulberry (tut) daraxtidan qo'lda qog'oz ishlab chiqarish jarayonini ko'rish mumkin. Samarqand qog'ozi dunyoga mashhur.", description_ru='Посёлок Конигиль в 10 км от Самарканда — центр древнего изготовления бумаги. Можно увидеть процесс ручного производства бумаги из тутового дерева. Самаркандская бумага знаменита во всём мире.', description_en='Konigil village, 10 km from Samarkand — an ancient paper-making center. See the handcrafting of paper from mulberry trees. Samarkand paper is world-famous.', short_desc_uz="Qadimiy qog'oz tayyorlash san'ati markazi", short_desc_ru='Центр древнего искусства изготовления бумаги', short_desc_en='Center of ancient paper-making art', address_uz="Konigil qishlog'i, Samarqand", address_ru='посёлок Конигиль, Самарканд', address_en='Konigil Village, Samarkand', city='Samarqand', latitude=39.67, longitude=66.975, phone='+998662345100', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.4, review_count=340, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "09:00-18:00"}', view_count=12000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge7004sjja2ziot2gxd', place_type='ATTRACTION', name_uz='Bolo Xauz majmuasi', name_ru='Комплекс Боло-Хауз', name_en='Bolo Haouz Complex', description_uz="Buxoro Arki ro'parasida joylashgan majmua. XVIII asr Bolo Xauz masjidi va katta hovuz. 20 ta ustunli aivan (ayvon) bilan bezatilgan. O'zbekiston pulida tasvirlangan joy.", description_ru='Комплекс напротив Бухарской Арки. Мечеть Боло-Хауз XVIII века и большой бассейн. Украшен айваном с 20 колоннами. Изображён на банкноте Узбекистана.', description_en='A complex opposite Bukhara Ark. The 18th-century Bolo Haouz mosque and large pool. Adorned with a 20-pillar aivan. Featured on Uzbekistan banknote.', short_desc_uz="O'zbekiston banknotidagi tarixiy majmua", short_desc_ru='Исторический комплекс с банкноты Узбекистана', short_desc_en='Historic complex featured on Uzbekistan banknote', address_uz='Ark maydoni, Buxoro', address_ru='Площадь Арк, Бухара', address_en='Ark Square, Bukhara', city='Buxoro', latitude=39.775, longitude=64.4295, phone='+998652261400', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.5, review_count=450, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "08:00-18:00"}', view_count=16000, historical_period='XVIII asr', owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge8004ujja225n76pp3', place_type='ATTRACTION', name_uz='Amir Temur maydoni', name_ru='Площадь Амира Тимура', name_en='Amir Timur Square', description_uz="Toshkentning markaziy maydoni — Amir Temur haykali bilan. 1993-yilda o'rnatilgan. Atrofida Davlat muzeyi, mehmonxona va bog'lar joylashgan. Toshkentning eng mashhur uchrashuv joyi.", description_ru='Центральная площадь Ташкента — со статуей Амира Тимура. Установлена в 1993 году. Вокруг расположены Государственный музей, отель и парки. Самое популярное место встреч.', description_en="Tashkent's central square — with the Amir Timur statue. Erected in 1993. Surrounded by the State Museum, hotel, and gardens. The city's most popular meeting place.", short_desc_uz='Toshkentning markaziy maydoni — Amir Temur haykali', short_desc_ru='Центральная площадь Ташкента — статуя Амира Тимура', short_desc_en='Central square of Tashkent — Amir Timur statue', address_uz="Amir Temur shoh ko'chasi, Toshkent", address_ru='проспект Амира Тимура, Ташкент', address_en='Amir Timur Avenue, Tashkent', city='Toshkent', latitude=41.2996, longitude=69.2406, phone='+998712701000', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.6, review_count=1230, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=True, working_hours='{"all": "00:00-24:00"}', view_count=52000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge9004wjja23dcmd7j0', place_type='ATTRACTION', name_uz="Toshkent Botanika bog'i", name_ru='Ботанический сад Ташкента', name_en='Tashkent Botanical Garden', description_uz="Toshkentdagi eng qadimiy bog' — Botanika bog'i. 1920-yilda tashkil etilgan. 4000 dan ortiq o'simlik turlari, yapon bog'i va gulli panjaralar. Oilaviy sayohat uchun ideal.", description_ru='Старейший парк Ташкента — Ботанический сад. Основан в 1920 году. Более 4000 видов растений, японский сад и цветочные арки. Идеален для семейного отдыха.', description_en="Tashkent's oldest park — the Botanical Garden. Established in 1920. Over 4,000 plant species, Japanese garden, and floral arches. Ideal for family outings.", short_desc_uz="Toshkentning eng qadimiy va keng bog'i", short_desc_ru='Старейший и крупнейший парк Ташкента', short_desc_en="Tashkent's oldest and largest garden", address_uz="Bog'doshlar ko'chasi, Toshkent", address_ru='улица Садоводов, Ташкент', address_en='Bogdoshlar Street, Tashkent', city='Toshkent', latitude=41.287, longitude=69.281, phone='+998712701100', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.3, review_count=670, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "08:00-20:00"}', view_count=19000, historical_period=None, owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewge9004yjja2auvot37u', place_type='ATTRACTION', name_uz='Kunya Ark', name_ru='Куня-Арк', name_en='Kunya Ark', description_uz="Xiva xonlarining qadimiy qarorgohi — Kunya Ark. XVII asrda qurilgan bu majmua Juma masjidi, hukumat binolari va hovuzni o'z ichiga oladi. Ichan Qal'aning eng muhim tarkibiy qismi.", description_ru='Древняя резиденция хивинских ханов — Куня-Арк. Построенный в XVII веке, этот комплекс включает пятничную мечеть, правительственные здания и бассейн. Важнейшая часть Ичан-Кала.', description_en='The ancient residence of Khiva khans — Kunya Ark. Built in the 17th century, this complex includes a Friday mosque, government buildings, and pool. An essential part of Ichan Kala.', short_desc_uz='Xiva xonlarining qadimiy qarorgohi', short_desc_ru='Древняя резиденция хивинских ханов', short_desc_en='Ancient residence of Khiva khans', address_uz="Ichan Qal'a, Xiva", address_ru='Ичан-Кала, Хива', address_en='Ichan Kala, Khiva', city='Xiva', latitude=41.3785, longitude=60.366, phone='+998623533500', website=None, telegram=None, instagram=None, image_url='/images/attractions/kunya-ark.jpg', gallery_images='[]', rating=4.6, review_count=520, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "08:00-18:00"}', view_count=18000, historical_period='XVII asr', owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewgea0050jja2j6hqh3ap', place_type='ATTRACTION', name_uz="Tosh Darvoza (G'arbiy darvoza)", name_ru='Таш Дарваза (Западные ворота)', name_en='Tosh Darvoza (Stone Gate)', description_uz="Ichan Qal'aning g'arbiy darvozasi — Tosh Darvoza. Xiva shahriga kirishning asosiy yo'li. Darvoza yonida sayohatchilar uchun do'konlar va kafelar. Chiroyli kechki yoritgichi.", description_ru='Западные ворота Ичан-Кала — Таш Дарваза. Главный вход в город Хива. Рядом с воротами магазины и кафе для путешественников. Красивая вечерняя подсветка.', description_en='The western gate of Ichan Kala — Tosh Darvoza. The main entrance to Khiva city. Shops and cafés for travelers near the gate. Beautiful evening illumination.', short_desc_uz="Ichan Qal'aning asosiy kirish darvozasi", short_desc_ru='Главные ворота Ичан-Кала', short_desc_en='Main entrance gate of Ichan Kala', address_uz='Tosh Darvoza, Xiva', address_ru='Таш Дарваза, Хива', address_en='Tosh Darvoza, Khiva', city='Xiva', latitude=41.377, longitude=60.361, phone='+998623534600', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.3, review_count=340, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "07:00-20:00"}', view_count=14000, historical_period='XIX asr', owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewgea0052jja25tcwd4el', place_type='ATTRACTION', name_uz="Samarqand bog'i", name_ru='Парк Самарканда', name_en='Samarkand Central Park', description_uz="Samarqand shahar markazidagi keng bog'. Attraksionlar, bolalar maydonchasi, oziq-ovqat joylari va yashil maydonlar. Mahalliy aholi va sayohatchilar dam olish uchun mashhur joy.", description_ru='Большой парк в центре города Самарканд. Аттракционы, детская площадка, точки питания и зелёные зоны. Популярное место отдыха для местных жителей и путешественников.', description_en='A large park in central Samarkand. Amusement rides, playground, food spots, and green areas. A popular recreation spot for locals and travelers.', short_desc_uz="Shahar markazidagi keng dam olish bog'i", short_desc_ru='Большой парк отдыха в центре города', short_desc_en='Large recreation park in the city center', address_uz="Bog' ko'chasi, Samarqand", address_ru='Парк улица, Самарканд', address_en='Park Street, Samarkand', city='Samarqand', latitude=39.648, longitude=66.944, phone='+998662346200', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.2, review_count=210, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=False, working_hours='{"all": "06:00-23:00"}', view_count=8700, historical_period=None, owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
db.add(Place(id='cmp7ewgea0054jja2f8st9q0q', place_type='ATTRACTION', name_uz='Lyabi Hauz majmuasi', name_ru='Комплекс Ляби-Хауз', name_en='Lyabi Hauz Complex', description_uz='Buxoro eng mashhur joylardan biri — Lyabi Hauz hovuz majmuasi. XVI-XVII asrlarda qurilgan katta hovuz, Nodir Devonbegi xonaqohi va kuluk. Kechasi chiroyli yoritiladi.', description_ru='Одно из самых известных мест Бухары — комплекс хауза Ляби-Хауз. Большой бассейн XVI-XVII веков, ханака Надир Деванбеги и чинар. Ночью красиво подсвечивается.', description_en="One of Bukhara's most famous spots — the Lyabi Hauz pool complex. A large pool from the 16th–17th centuries, Nodir Devonbegi khanqah, and mulberry tree. Beautifully lit at night.", short_desc_uz='Buxoroning eng mashhur hovuz majmuasi', short_desc_ru='Самый известный хауз Бухары', short_desc_en="Bukhara's most famous pool complex", address_uz='Lyabi Hauz maydoni, Buxoro', address_ru='Площадь Ляби-Хауз, Бухара', address_en='Lyabi Hauz Square, Bukhara', city='Buxoro', latitude=39.777, longitude=64.426, phone='+998652260300', website=None, telegram=None, instagram=None, image_url=None, gallery_images='[]', rating=4.7, review_count=890, price_from=None, price_to=None, currency='UZS', is_halal=False, is_featured=True, working_hours='{"all": "00:00-24:00"}', view_count=35000, historical_period='XVI-XVII asrlar', owner_id=None, category_id='cmp7ewgbp000djja2moyir50q'))
