db.add(Review(id='cmp7ewgeg005ejja2wbz6d8zq', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgdi003ejja20s3iq0cq', rating=5, comment_uz="Uthmon Qur'onini ko'rish hayotimdagi eng katta taassurotlardan biri bo'ldi. Kompleks juda chiroyli va tartibli.", comment_ru='Увидеть Османовский Коран — одно из самых больших впечатлений в моей жизни. Комплекс очень красивый и ухоженный.', comment_en='Seeing the Uthman Quran was one of the biggest impressions of my life. The complex is beautiful and well-maintained.'))
db.add(Review(id='cmp7ewgei005ijja2dkp51gyh', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgde002yjja2pi1tzf1c', rating=5, comment_uz="47 metr balandlikdagi minorani ko'rish hayotimdagi eng katta taassurot edi. Me'morchlik durdonasi!", comment_ru='Увидеть 47-метровый минарет — одно из самых больших впечатлений в жизни. Жемчужина архитектуры!', comment_en='Seeing the 47-meter minaret was one of the biggest impressions of my life. An architectural jewel!'))
db.add(Review(id='cmp7ewgei005kjja2ygrh0vw3', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgcn0017jja2lw13pvxe', rating=5, comment_uz='Safina Boutique Hotel — Buxoro eski shahrida qolishning eng yaxshi usuli. Oilaviy muhit va ajoyib taomlar.', comment_ru='Safina Boutique Hotel — лучший способ остановиться в старом городе Бухары. Семейная атмосфера и отличная еда.', comment_en='Safina Boutique Hotel — the best way to stay in Bukhara old town. Family atmosphere and great food.'))
db.add(Review(id='cmp7ewgej005mjja2zkd8lrv4', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgd20023jja2s7u63p2m', rating=4, comment_uz="Lyabi Hauzda hovuz bo'yi choy ichish — Buxoro sayohatining eng yaxshi lazzati. Taomlar ham mazali.", comment_ru='Чай у хауза Ляби-Хауз — лучшее удовольствие в поездке по Бухаре. Блюда тоже вкусные.', comment_en='Tea by the Lyabi Hauz pool — the best pleasure in a Bukhara trip. Food is also tasty.'))
db.add(Review(id='cmp7ewgeg005ajja2yne3erqc', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgcm0012jja24c2rmfo8', rating=5, comment_uz="Xizmat a'lo, xonalar juda qulay. Registon maydoni ko'rinishi ajoyib. Albatta tavsiya qilaman!", comment_ru='Обслуживание отличное, номера очень удобные. Вид на площадь Регистан потрясающий. Однозначно рекомендую!', comment_en='Excellent service, very comfortable rooms. The view of Registan Square is amazing. Highly recommend!'))
db.add(Review(id='cmp7ewgeh005gjja26heqrcic', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgcn0018jja2e7uwpp3n', rating=4, comment_uz="Mehmonxona tarixiy binoda joylashgan va atmosfera juda ajoyib. Xizmat yaxshi, lekin ba'zi xonalar ta'mirlashni talab qiladi.", comment_ru='Отель расположен в историческом здании с прекрасной атмосферой. Обслуживание хорошее, но некоторые номера требуют ремонта.', comment_en='The hotel is in a historic building with a wonderful atmosphere. Good service, though some rooms need renovation.'))
db.add(Review(id='cmp7ewgel005sjja2wj6oc4m4', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgcq001ijja20n9ye56t', rating=5, comment_uz="Wyndham Tashkent — poytaxtdagi eng yaxshi mehmonxona. Xizmat, ovqat va hovuz barchasi a'lo darajada.", comment_ru='Wyndham Tashkent — лучший отель столицы. Сервис, еда и бассейн — всё на высшем уровне.', comment_en='Wyndham Tashkent — the best hotel in the capital. Service, food, and pool — all top-notch.'))
db.add(Review(id='cmp7ewgel005ujja2jfjfkulj', user_id='cmp7ewgbh0001jja2xqwcwz69', place_id='cmp7ewgde002wjja2v239szqn', rating=5, comment_uz="Ichan Qal'a — haqiqatan ham ochiq osmon muzeyi. Har bir ko'cha, har bir bino tarix gapiradi. Bir kun yetarli emas!", comment_ru='Ичан-Кала — настоящий музей под открытым небом. Каждая улица, каждое здание рассказывает историю. Одного дня не хватает!', comment_en='Ichan Kala is truly an open-air museum. Every street, every building tells a story. One day is not enough!'))
